/**
 * Returns the tile keys needed to cover a ~25km radius around the given coordinates.
 */
function getNeededTileKeys(lat: number, lon: number): string[] {
  const keys: string[] = [];
  // Load the tile containing the point plus all 8 neighbors
  const baseLat = Math.floor(lat);
  const baseLon = Math.floor(lon);
  for (let dLat = -1; dLat <= 1; dLat++) {
    for (let dLon = -1; dLon <= 1; dLon++) {
      const key = `${baseLat + dLat}_${baseLon + dLon}`;
      if (tileMap[key]) keys.push(key);
    }
  }
  return keys;
}

/**
 * Loads toilets from relevant tiles near the given coordinates.
 */
export function loadNearbyTiles(lat: number, lon: number): RawToilet[] {
  const keys = getNeededTileKeys(lat, lon);
  const all: RawToilet[] = [];
  for (const key of keys) {
    all.push(...tileMap[key]());
  }
  return all;
}
